/* wms-inbound-order-cancel-sql-oracle.xml - selectInterfaceInboundCancelList - 입고 취소 수신 인터페이스 - 등록 대상 조회 */
SELECT CTKEY
	 , OWKEY
	 , IBHDKEY
  FROM TWORK_INFO_IB_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ORHDKEY = #{orhdkey}

mapper.update:
UPDATE TWORK_INFO_IB_HD
   SET IBSTATUSCD = '99'

	 , RIPRGRSTATUSCD = #{riprgrstatuscd}

	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}

UPDATE TWORK_INFO_IB_DT
   SET IBDTSTATUSCD = '99'

	, RIPRGRSTATUSCD = #{riprgrstatuscd}

	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}

mapper.select:
/* wms-inbound-order-cancel-sql-oracle.xml - selectInboundReturnWblno - 운송장 내역 조회 */
SELECT *
  FROM TWORK_INFO_IBRET_WBLNO
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND WBLNO = #{wblno}

mapper.update:
UPDATE TWORK_INFO_IBRET_WBLNO
   SET WBLPRGRSTATUSCD = '60'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND WBLNO = #{wblno}

mapper.select:
/* wms-inbound-order-cancel-sql-oracle.xml - selectInboundReturnWblprgrstatusCnt - 운송장 진행상태 Count 조회 */
SELECT SUM(CASE WHEN WBLPRGRSTATUSCD = '10' THEN 1 ELSE 0 END) AS RETURN_CNT
	 , SUM(CASE WHEN WBLPRGRSTATUSCD = '20' THEN 1 ELSE 0 END) AS REQ_CNT
	 , SUM(CASE WHEN WBLPRGRSTATUSCD = '30' THEN 1 ELSE 0 END) AS PRGR_CNT
	 , SUM(CASE WHEN WBLPRGRSTATUSCD = '40' THEN 1 ELSE 0 END) AS COMPL_CNT
	 , SUM(CASE WHEN WBLPRGRSTATUSCD = '60' THEN 1 ELSE 0 END) AS CANCEL_CNT
	 , COUNT(*) AS TOTAL_CNT
  FROM TWORK_INFO_IBRET_WBLNO
 WHERE CTKEY  = #{ctkey}
   AND OWKEY  = #{owkey}
   AND IBHDKEY = #{ibhdkey}

/* wms-inbound-order-cancel-sql-oracle.xml - selectInboundReturnWblnoSbm - 반품 운송장 접수 내역 조회 */
SELECT *
  FROM TWORK_INFO_IBRET_WBLNO_SBM
 WHERE CTKEY = #{ctkey}
   AND CLAIMNO = #{claimno}
   AND CUSTORDNO = #{custordno}
